unsigned long long run_event_based_simulation_optimization_1(Inputs in, SimulationData GSD, int mype)
{
	char * optimization_name = "Optimization 1 - Kernel splitting + full material & energy sort";

	if( mype == 0) printf("Simulation Kernel:\"%s\"\n", optimization_name);

	if( mype == 0) printf("Allocating additional data required by optimized kernel...\n");

	size_t sz;
	size_t total_sz = 0;

	sz = in.lookups * sizeof(double);
	GSD.p_energy_samples = (double *) malloc(sz);
	total_sz = total_sz + (sz);
	GSD.length_p_energy_samples = in.lookups;

	sz = in.lookups * sizeof(int);
	GSD.mat_samples = (int *) malloc(sz);
	total_sz = total_sz + (sz);
	GSD.length_mat_samples = in.lookups;

	if( mype == 0) printf("Allocated an additional %.0lf MB of data on GPU.\n", total_sz/1024.0/1024.0);

	int threads = 256;
	int blocks = (in.lookups + threads - 1) / threads;

	sampling_kernel<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaDeviceSynchronize());

	if(mype == 0) printf("finished sampling...\n");

	unsigned long long verification = 0;
	unsigned long long * d_verification;
	gpuErrchk(cudaMalloc(&d_verification, sizeof(unsigned long long)));
	gpuErrchk(cudaMemcpy(d_verification, &verification, sizeof(unsigned long long), cudaMemcpyHostToDevice));

	xs_lookup_kernel_optimization_1<<<blocks, threads>>>(in, GSD, d_verification);
	gpuErrchk(cudaDeviceSynchronize());

	gpuErrchk(cudaMemcpy(&verification, d_verification, sizeof(unsigned long long), cudaMemcpyDeviceToHost));
	cudaFree(d_verification);

	return verification;
}

unsigned long long run_event_based_simulation_optimization_2(Inputs in, SimulationData GSD, int mype)
{
	if( mype == 0) printf("Running Optimization 2 (Baseline implementation used for compatibility)\n");
	return run_event_based_simulation_baseline(in, GSD, mype);
}

unsigned long long run_event_based_simulation_optimization_3(Inputs in, SimulationData GSD, int mype)
